<x-layouts.app :title="$album->name"><h1>{{ $album->name }}</h1><p>{{ $album->description }}</p>@if($photos->isEmpty())<x-empty-state title="Album masih kosong" message="Unggah foto dan pilih album ini." />@else<div class="row g-3">@foreach($photos as $photo)<div class="col-6 col-md-4"><a href="{{ route('photos.show',$photo) }}"><img loading="lazy" class="img-fluid rounded" src="{{ Storage::url($photo->thumbnail_path) }}" alt="{{ $photo->caption ?: 'Foto dalam album '.$album->name }}"></a></div>@endforeach</div>{{ $photos->links() }}@endif</x-layouts.app>
